/** Return an HTML string with token spans applied. */
export function highlight(code, language) {
  const words = new Set(KEYWORDS[language] || KEYWORDS.python);
  const escaped = escapeHtml(code);

  // Order matters: comments first (line + block) so we don't accidentally
  // token-highlight code that lives inside a comment.
  let out = escaped
  // block comments /* ... */ (multiline)
  .replace(/\/\*[\s\S]*?\*\//g, m => `<span class="hl-token-comment">${m}</span>`)
  // hash and slash-slash line comments — kept simple, not perfect.
  .replace(/(^|[^:])(#[^\n]*|\/\/[^\n]*)/g, (_m, p1, p2) => `${p1}<span class="hl-token-comment">${p2}</span>`)
  // strings — greedy match single/double/triple quoted
  .replace(/("""[\s\S]*?"""|'''[\s\S]*?'''|"(?:\\.|[^"\\])*"|'(?:\\.|[^'\\])*'|`(?:\\.|[^`\\])*`)/g, m => `<span class="hl-token-string">${m}</span>`)
  // numbers
  .replace(/\b(\d+(?:\.\d+)?)\b/g, `<span class="hl-token-number">$1</span>`);

  // Keyword pass — split into HTML-safe chunks so we skip existing spans.
  out = out.replace(/([A-Za-z_][A-Za-z0-9_]*)/g, m => {
    if (words.has(m)) return `<span class="hl-token-keyword">${m}</span>`;
    return m;
  });

  // Function-call detection: identifier followed by "(".
  out = out.replace(/([A-Za-z_][A-Za-z0-9_]*)(\s*)(?=\()/g, (m, name, ws) => {
    if (/hl-token-keyword">/.test(m)) return m; // already highlighted as keyword
    return `<span class="hl-token-func">${name}</span>${ws}`;
  });
  return out;
}

