/**
 * Lightweight, dependency-free syntax highlighter for the three tiny
 * per-language token sets we care about (Python, JS/TS, Java/C/C++/Go).
 *
 * We deliberately avoid pulling in the full Prism runtime because we only
 * need to colour short snippets shown inside cards — accuracy is bounded
 * anyway by the fact that the LLM sometimes returns partial code slices.
 */

const KEYWORDS: Record<string, string[]> = {
  python: [
    'def','return','if','elif','else','for','while','in','not','and','or','import','from','as','class','with','try','except','finally','raise','lambda','pass','yield','True','False','None','self','print','len','range','enumerate','sorted','map','filter','sum',
  ],
  javascript: [
    'const','let','var','function','return','if','else','for','while','of','in','do','switch','case','break','continue','class','extends','new','this','import','export','from','default','async','await','try','catch','finally','throw','typeof','instanceof','true','false','null','undefined','console',
  ],
  typescript: [
    'const','let','var','function','return','if','else','for','while','of','in','type','interface','class','extends','implements','new','this','import','export','from','default','async','await','try','catch','finally','throw','typeof','instanceof','public','private','protected','readonly','true','false','null','undefined',
  ],
  java: ['public','private','protected','static','final','class','interface','extends','implements','void','int','long','float','double','boolean','char','String','if','else','for','while','do','switch','case','break','continue','return','new','this','try','catch','finally','throw','throws','true','false','null'],
  c: ['int','long','float','double','char','void','if','else','for','while','do','switch','case','break','continue','return','struct','typedef','const','static','sizeof','include','define'],
  cpp: ['int','long','float','double','char','void','bool','if','else','for','while','do','switch','case','break','continue','return','struct','class','public','private','protected','template','typename','namespace','std','const','static','sizeof','include','define','true','false','nullptr'],
  go: ['func','var','const','if','else','for','range','return','package','import','type','struct','interface','map','chan','go','defer','select','switch','case','break','continue','true','false','nil'],
};

function escapeHtml(s: string): string {
  return s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

/** Return an HTML string with token spans applied. */
export function highlight(code: string, language: string): string {
  const words = new Set(KEYWORDS[language] || KEYWORDS.python);
  const escaped = escapeHtml(code);

  // Order matters: comments first (line + block) so we don't accidentally
  // token-highlight code that lives inside a comment.
  let out = escaped
    // block comments /* ... */ (multiline)
    .replace(/\/\*[\s\S]*?\*\//g, (m) => `<span class="hl-token-comment">${m}</span>`)
    // hash and slash-slash line comments — kept simple, not perfect.
    .replace(/(^|[^:])(#[^\n]*|\/\/[^\n]*)/g, (_m, p1, p2) => `${p1}<span class="hl-token-comment">${p2}</span>`)
    // strings — greedy match single/double/triple quoted
    .replace(/("""[\s\S]*?"""|'''[\s\S]*?'''|"(?:\\.|[^"\\])*"|'(?:\\.|[^'\\])*'|`(?:\\.|[^`\\])*`)/g, (m) => `<span class="hl-token-string">${m}</span>`)
    // numbers
    .replace(/\b(\d+(?:\.\d+)?)\b/g, `<span class="hl-token-number">$1</span>`);

  // Keyword pass — split into HTML-safe chunks so we skip existing spans.
  out = out.replace(/([A-Za-z_][A-Za-z0-9_]*)/g, (m) => {
    if (words.has(m)) return `<span class="hl-token-keyword">${m}</span>`;
    return m;
  });

  // Function-call detection: identifier followed by "(".
  out = out.replace(/([A-Za-z_][A-Za-z0-9_]*)(\s*)(?=\()/g, (m, name, ws) => {
    if (/hl-token-keyword">/.test(m)) return m; // already highlighted as keyword
    return `<span class="hl-token-func">${name}</span>${ws}`;
  });

  return out;
}
